#include <chrono>
#include <cmath>
#include <cstdio>
#include <cstdlib>
#include <iostream>
#include <iomanip>
#include <limits>
#include <utility>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

static void initialize_data(float* f) {
  constexpr float PI = 3.14159265358979323846f;

  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (0 == i || N - 1 == i) {
        f[IDX(i, j)] = sinf(j * 2.0f * PI / (N - 1));
      } else if (0 == j || N - 1 == j) {
        f[IDX(i, j)] = sinf(i * 2.0f * PI / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

int main() {
  auto start_time = std::chrono::steady_clock::now();

  constexpr std::size_t NN = static_cast<std::size_t>(N) * static_cast<std::size_t>(N);

  float* f = (float*)aligned_alloc(64, NN * sizeof(float));
  float* f_old = (float*)aligned_alloc(64, NN * sizeof(float));

  initialize_data(f);
  initialize_data(f_old);

  #pragma omp target enter data map(to: f[0:NN], f_old[0:NN])

  float error = std::numeric_limits<float>::max();
  const float tolerance = 1.e-5f;

  const int max_iters = 10000;
  int num_iters = 0;

  auto start = std::chrono::steady_clock::now();

  while (tolerance < error && max_iters > num_iters) {
    error = 0.0f;

    if ((num_iters & 1) == 0) {
      #pragma omp target teams distribute parallel for collapse(2) reduction(+:error)
      for (int j = 1; j <= N - 2; ++j) {
        for (int i = 1; i <= N - 2; ++i) {
          float new_val = 0.25f * (f_old[IDX(i + 1, j)] +
                                   f_old[IDX(i - 1, j)] +
                                   f_old[IDX(i, j + 1)] +
                                   f_old[IDX(i, j - 1)]);
          f[IDX(i, j)] = new_val;
          float df = new_val - f_old[IDX(i, j)];
          error += df * df;
        }
      }
    } else {
      #pragma omp target teams distribute parallel for collapse(2) reduction(+:error)
      for (int j = 1; j <= N - 2; ++j) {
        for (int i = 1; i <= N - 2; ++i) {
          float new_val = 0.25f * (f[IDX(i + 1, j)] +
                                   f[IDX(i - 1, j)] +
                                   f[IDX(i, j + 1)] +
                                   f[IDX(i, j - 1)]);
          f_old[IDX(i, j)] = new_val;
          float df = new_val - f[IDX(i, j)];
          error += df * df;
        }
      }
    }

    error = sqrtf(error / (N * N));

    if (num_iters % 1000 == 0) {
      std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
    }

    ++num_iters;
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

  if (error <= tolerance && max_iters > num_iters) {
    std::cout << "PASS" << std::endl;
  } else {
    std::cout << "FAIL" << std::endl;
    #pragma omp target exit data map(delete: f[0:NN], f_old[0:NN])
    free(f);
    free(f_old);
    return -1;
  }

  #pragma omp target exit data map(delete: f[0:NN], f_old[0:NN])
  free(f);
  free(f_old);

  auto end_time = std::chrono::steady_clock::now();
  auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
  double duration = total_time * 1e-9;
  std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

  return 0;
}
